# -*- coding: utf-8 -*-
"""Generate two academic papers with proper Word footnotes."""
import re
import os
from docx import Document
from docx.shared import Pt, Cm
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.oxml.ns import qn
from docx.oxml import OxmlElement
from docx.opc.part import Part
from docx.opc.packuri import PackURI


def set_font(run, fname='SimSun', size=12, bold=False):
    run.font.size = Pt(size)
    run.font.name = fname
    run.bold = bold
    rPr = run._element.get_or_add_rPr()
    rFonts = OxmlElement('w:rFonts')
    rFonts.set(qn('w:eastAsia'), fname)
    rFonts.set(qn('w:ascii'), fname)
    rFonts.set(qn('w:hAnsi'), fname)
    rPr.insert(0, rFonts)


def escape_xml(text):
    return text.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')


def build_footnotes_xml(footnotes_list):
    W_NS = 'http://schemas.openxmlformats.org/wordprocessingml/2006/main'
    R_NS = 'http://schemas.openxmlformats.org/officeDocument/2006/relationships'
    xml_parts = [
        '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
        f'<w:footnotes xmlns:w="{W_NS}" xmlns:r="{R_NS}">',
        '  <w:footnote w:type="separator" w:id="-1">',
        '    <w:p><w:r><w:separator/></w:r></w:p>',
        '  </w:footnote>',
        '  <w:footnote w:type="continuationSeparator" w:id="0">',
        '    <w:p><w:r><w:continuationSeparator/></w:r></w:p>',
        '  </w:footnote>',
    ]
    for i, fn_text in enumerate(footnotes_list):
        fn_id = i + 1
        escaped = escape_xml(fn_text)
        xml_parts.extend([
            f'  <w:footnote w:id="{fn_id}">',
            '    <w:p>',
            '      <w:pPr><w:pStyle w:val="FootnoteText"/></w:pPr>',
            '      <w:r>',
            '        <w:rPr><w:rStyle w:val="FootnoteReference"/></w:rPr>',
            '        <w:footnoteRef/>',
            '      </w:r>',
            '      <w:r>',
            '        <w:rPr>',
            '          <w:rFonts w:eastAsia="SimSun" w:ascii="SimSun" w:hAnsi="SimSun"/>',
            '          <w:sz w:val="18"/>',
            '          <w:szCs w:val="18"/>',
            '        </w:rPr>',
            f'        <w:t xml:space="preserve"> {escaped}</w:t>',
            '      </w:r>',
            '    </w:p>',
            '  </w:footnote>',
        ])
    xml_parts.append('</w:footnotes>')
    return '\n'.join(xml_parts)


def add_footnote_styles(doc):
    styles_elem = doc.styles.element
    existing_ids = set()
    for s in styles_elem.findall(qn('w:style')):
        sid = s.get(qn('w:styleId'))
        if sid:
            existing_ids.add(sid)

    if 'FootnoteText' not in existing_ids:
        ft = OxmlElement('w:style')
        ft.set(qn('w:type'), 'paragraph')
        ft.set(qn('w:styleId'), 'FootnoteText')
        n = OxmlElement('w:name')
        n.set(qn('w:val'), 'footnote text')
        ft.append(n)
        bo = OxmlElement('w:basedOn')
        bo.set(qn('w:val'), 'Normal')
        ft.append(bo)
        pPr = OxmlElement('w:pPr')
        sl = OxmlElement('w:spacing')
        sl.set(qn('w:after'), '0')
        sl.set(qn('w:line'), '240')
        sl.set(qn('w:lineRule'), 'auto')
        pPr.append(sl)
        ft.append(pPr)
        rPr = OxmlElement('w:rPr')
        sz = OxmlElement('w:sz')
        sz.set(qn('w:val'), '18')
        rPr.append(sz)
        szCs = OxmlElement('w:szCs')
        szCs.set(qn('w:val'), '18')
        rPr.append(szCs)
        rFonts = OxmlElement('w:rFonts')
        rFonts.set(qn('w:eastAsia'), 'SimSun')
        rFonts.set(qn('w:ascii'), 'SimSun')
        rFonts.set(qn('w:hAnsi'), 'SimSun')
        rPr.append(rFonts)
        ft.append(rPr)
        styles_elem.append(ft)

    if 'FootnoteReference' not in existing_ids:
        fr = OxmlElement('w:style')
        fr.set(qn('w:type'), 'character')
        fr.set(qn('w:styleId'), 'FootnoteReference')
        n = OxmlElement('w:name')
        n.set(qn('w:val'), 'footnote reference')
        fr.append(n)
        rPr = OxmlElement('w:rPr')
        va = OxmlElement('w:vertAlign')
        va.set(qn('w:val'), 'superscript')
        rPr.append(va)
        fr.append(rPr)
        styles_elem.append(fr)


def make_doc(title, subtitle, sections, path):
    doc = Document()
    style = doc.styles['Normal']
    style.font.name = 'SimSun'
    style.font.size = Pt(12)
    rp = style.element.get_or_add_rPr()
    rf = rp.find(qn('w:rFonts'))
    if rf is None:
        rf = OxmlElement('w:rFonts')
        rp.insert(0, rf)
    rf.set(qn('w:eastAsia'), 'SimSun')

    add_footnote_styles(doc)

    for sec in doc.sections:
        sec.top_margin = Cm(2.54)
        sec.bottom_margin = Cm(2.54)
        sec.left_margin = Cm(3.18)
        sec.right_margin = Cm(3.18)

    pt = doc.add_paragraph()
    pt.alignment = WD_ALIGN_PARAGRAPH.CENTER
    rt = pt.add_run(title)
    set_font(rt, 'SimHei', 18, True)
    pt.paragraph_format.space_after = Pt(6)

    ps = doc.add_paragraph()
    ps.alignment = WD_ALIGN_PARAGRAPH.CENTER
    rs = ps.add_run(subtitle)
    set_font(rs, 'SimSun', 14)
    ps.paragraph_format.space_after = Pt(4)

    pi = doc.add_paragraph()
    pi.alignment = WD_ALIGN_PARAGRAPH.CENTER
    ri = pi.add_run('\u59d3\u540d\uff1a________    \u5b66\u53f7\uff1a________')
    set_font(ri, 'SimSun', 12)
    pi.paragraph_format.space_after = Pt(12)

    all_fn = []
    fn_offset = 0

    for sec_heading, sec_paras, sec_fns in sections:
        if sec_heading:
            ph = doc.add_paragraph()
            rh = ph.add_run(sec_heading)
            set_font(rh, 'SimHei', 14, True)
            ph.paragraph_format.space_before = Pt(12)
            ph.paragraph_format.space_after = Pt(6)

        for para in sec_paras:
            p = doc.add_paragraph()
            p.paragraph_format.first_line_indent = Cm(0.74)
            p.paragraph_format.line_spacing = 1.5
            parts = re.split(r'(\{fn:\d+\})', para)
            for part in parts:
                m = re.match(r'\{fn:(\d+)\}', part)
                if m:
                    fn_num = int(m.group(1))
                    fn_id = fn_offset + fn_num
                    run = p.add_run()
                    r_elem = run._element
                    rPr = OxmlElement('w:rPr')
                    rStyle = OxmlElement('w:rStyle')
                    rStyle.set(qn('w:val'), 'FootnoteReference')
                    rPr.append(rStyle)
                    r_elem.append(rPr)
                    fnRef = OxmlElement('w:footnoteReference')
                    fnRef.set(qn('w:id'), str(fn_id))
                    r_elem.append(fnRef)
                elif part:
                    run = p.add_run(part)
                    set_font(run, 'SimSun', 12)

        fn_count = len(sec_fns)
        all_fn.extend(sec_fns)
        fn_offset += fn_count

    # Create footnotes XML part
    fn_xml = build_footnotes_xml(all_fn)
    fn_partname = PackURI('/word/footnotes.xml')
    fn_content_type = 'application/vnd.openxmlformats-officedocument.wordprocessingml.footnotes+xml'
    fn_part = Part(fn_partname, fn_content_type, fn_xml.encode('utf-8'), doc.part.package)
    fn_rel_type = 'http://schemas.openxmlformats.org/officeDocument/2006/relationships/footnotes'
    doc.part.relate_to(fn_part, fn_rel_type)

    # Set footnote properties: circled numbers, restart per page
    sectPr = doc.sections[0]._sectPr
    footnotePr = OxmlElement('w:footnotePr')
    numFmt = OxmlElement('w:numFmt')
    numFmt.set(qn('w:val'), 'decimalEnclosedCircle')
    footnotePr.append(numFmt)
    numRestart = OxmlElement('w:numRestart')
    numRestart.set(qn('w:val'), 'eachPage')
    footnotePr.append(numRestart)
    sectPr.insert(0, footnotePr)

    doc.save(path)
    total_chars = sum(len(re.sub(r'\{fn:\d+\}', '', p)) for _, paras, _ in sections for p in paras)
    print(f'Saved: {path} ({total_chars} chars, {len(all_fn)} footnotes)')


